content.problemStatement:
Chef loves games! But he likes to invent his own. Now he plays game "Digit Jump". Chef has a sequence of digits S1,S2,…,SNS_{1}, S_{2}, \ldots , S_{N}S1​,S2​,…,SN​. He is staying in the first digit S1S_{1}S1​ and wants to reach the last digit SNS_{N}SN​ in the minimal number of jumps.

While staying in some index iii Chef can jump into i−1i - 1i−1 and i+1i + 1i+1, but he can't jump out from sequence. Or he can jump into any digit with the same value SiS_iSi​.

Help Chef to find the minimal number of jumps he need to reach digit SNS_{N}SN​ from digit S1S_1S1​.&nbsp;

code.C:
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100005

int main() {
    char s[MAX];
    scanf("%s", s);
    int n = strlen(s);
    int jumps = 0;
    int visited[n];
    for (int i = 0; i < n; i++) visited[i] = 0;
    int queue[n];
    int front = 0, rear = 0;
    queue[rear++] = 0;
    visited[0] = 1;
    while (front < rear) {
        int u = queue[front++];
        if (u == n - 1) break;
        if (u > 0 && !visited[u - 1]) {
            queue[rear++] = u - 1;
            visited[u - 1] = 1;
        }
        if (u < n - 1 && !visited[u + 1]) {
            queue[rear++] = u + 1;
            visited[u + 1] = 1;
        }
        for (int i = 0; i < n; i++) {
            if (s[i] == s[u] && !visited[i]) {
                queue[rear++] = i;
                visited[i] = 1;
            }
        }
        jumps++;
    }
    printf("%d\n", jumps);
    return 0;
}

code.C++:
#include <iostream>
#include <queue>
#include <vector>
using namespace std;

int main() {
    string s;
    cin >> s;
    int n = s.length();
    int jumps = 0;
    vector<bool> visited(n, false);
    queue<int> q;
    q.push(0);
    visited[0] = true;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; i++) {
            int u = q.front();
            q.pop();
            if (u == n - 1) break;
            if (u > 0 && !visited[u - 1]) {
                q.push(u - 1);
                visited[u - 1] = true;
            }
            if (u < n - 1 && !visited[u + 1]) {
                q.push(u + 1);
                visited[u + 1] = true;
            }
            for (int j = 0; j < n; j++) {
                if (s[j] == s[u] && !visited[j]) {
                    q.push(j);
                    visited[j] = true;
                }
            }
        }
        jumps++;
    }
    cout << jumps << endl;
    return 0;
}

code.Java:
import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int n = s.length();
        int jumps = 0;
        boolean[] visited = new boolean[n];
        Queue<Integer> q = new LinkedList<>();
        q.add(0);
        visited[0] = true;
        while (!q.isEmpty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int u = q.poll();
                if (u == n - 1) break;
                if (u > 0 && !visited[u - 1]) {
                    q.add(u - 1);
                    visited[u - 1] = true;
                }
                if (u < n - 1 && !visited[u + 1]) {
                    q.add(u + 1);
                    visited[u + 1] = true;
                }
                for (int j = 0; j < n; j++) {
                    if (s.charAt(j) == s.charAt(u) && !visited[j]) {
                        q.add(j);
                        visited[j] = true;
                    }
                }
            }
            jumps++;
        }
        System.out.println(jumps);
    }
}

